export type RunAccepted = {
    id: string;
    type: 'workflow' | 'agent';
    finished: false;
    source?: RunSource;
};

export type Run = {
    id: string;
    type: 'workflow' | 'agent';
    /**
     * True when the run has reached a terminal status.
     */
    finished: boolean;
    /**
     * Deterministic pseudo-random rank in [0, 1) for this run within the tenant. Use with a sample rate threshold to review a stable subset.
     */
    sampleRank: number;
    timing: RunTiming;
    source: RunSource;
    trigger: RunTrigger;
    /**
     * Present only when the run is eval-scoped.
     */
    eval?: RunEval;
    /**
     * Completed runs only.
     */
    output?: {
        [key: string]: unknown;
    } | null;
    /**
     * Completed runs only. Download with GET /api/v1/runs/:id/artifacts/:path.
     */
    files?: Array<RunArtifact>;
    /**
     * Terminal failure message. Null when the run succeeded or is still in flight.
     */
    error?: RunError;
    /**
     * `expand=input`.
     */
    input?: RunInput;
    /**
     * `expand=usage`. Null for old runs without telemetry.
     */
    usage?: RunUsage | null;
    /**
     * Slim execution metadata always present. Pass `expand=execution` to replace with full RunExecution (WorkflowRunExecution or AgentRunExecution depending on run type).
     */
    execution: RunExecutionMeta | RunExecution;
    /**
     * `expand=debug`.
     */
    debug?: RunDebug;
};

export type RunArtifact = {
    name: string;
    /**
     * `input`, `output`, `debug`, `report`, or another stable artifact role.
     */
    role: string;
    /**
     * Canonical artifact path for GET /api/v1/runs/:id/artifacts/:path.
     */
    path: string;
    /**
     * Workflow step that produced the file, when known.
     */
    stepName?: string;
    contentType?: string | null;
    size?: number | null;
};

export type RunInput = {
    /**
     * Input arguments the run was started with.
     */
    args: unknown;
    /**
     * Uploaded input files (agent runs only).
     */
    files?: Array<RunFile>;
    /**
     * Caller-supplied run metadata, if any.
     */
    metadata?: unknown;
};

export type RunFile = {
    name: string;
};

export type RunUsage = {
    tokens: {
        input: number | null;
        output: number | null;
        cacheRead: number | null;
        cacheWrite: number | null;
    };
    creditsCharged: number | null;
    durationMs: number | null;
    /**
     * LLM call count (workflow runs only).
     */
    llmCallCount?: number;
    /**
     * OCR pages processed (workflow runs only).
     */
    ocrPagesProcessed?: number;
    /**
     * Agent conversation turns (agent runs only).
     */
    agentTurns?: number | null;
};

export type RunExecution = WorkflowRunExecution | AgentRunExecution;

export type WorkflowRunExecution = {
    status: ExecutionStatus;
    /**
     * Whether the completed output matched the workflow or agent output schema.
     */
    schemaValid: boolean | null;
    /**
     * Experiment batch id when the run is part of a batch.
     */
    batchId: string | null;
    retry: RunExecutionRetry;
    review?: RunReview | null;
    /**
     * Per-step executions of the workflow run.
     */
    steps: Array<unknown>;
    /**
     * Workflow definition snapshot captured when the run was created.
     */
    definitionSnapshot?: unknown | null;
    /**
     * Ground-truth expected output and files.
     */
    expected?: {
        output?: unknown;
        files?: Array<RunFile>;
    };
};

export type RunReview = {
    id: string;
    verdict: 'correct' | 'incorrect' | null;
    status: 'open' | 'closed' | 'wont_fix';
    note: string;
    correctedOutput?: unknown | null;
    /**
     * User id of the last reviewer. Read-only; set from the authenticated user or API key creator.
     */
    reviewedBy: string | null;
    /**
     * Email of the last reviewer. Read-only; set from the authenticated user or API key creator.
     */
    reviewedByEmail: string | null;
    reviewedAt: string;
    /**
     * User id recorded when the review was closed. Read-only; set when status becomes closed or wont_fix.
     */
    closedBy: string | null;
    /**
     * Email recorded when the review was closed. Read-only; set when status becomes closed or wont_fix.
     */
    closedByEmail: string | null;
    closedAt: string | null;
    closedNote: string | null;
    createdAt: string;
    updatedAt: string;
    corrections: Array<RunReviewCorrection>;
};

export type RunReviewCorrection = {
    id: string;
    kind: 'field' | 'file';
    /**
     * JSON Pointer for field corrections, or canonical artifact path for file reviews.
     */
    path: string;
    label: string | null;
    originalValue?: unknown | null;
    correctedValue?: unknown | null;
    note: string;
    correctedArtifactPath?: string | null;
    createdAt: string;
    updatedAt: string;
};

export type AgentRunExecution = {
    status: ExecutionStatus;
    /**
     * Whether the completed output matched the workflow or agent output schema.
     */
    schemaValid: boolean | null;
    /**
     * Experiment batch id when the run is part of a batch.
     */
    batchId: string | null;
    retry: RunExecutionRetry;
    review?: RunReview | null;
    files: {
        /**
         * Output artifacts the agent produced.
         */
        output: Array<RunFile>;
    };
    /**
     * Ground-truth expected output and files.
     */
    expected?: {
        output?: unknown;
        files?: Array<RunFile>;
    };
    /**
     * Expected-vs-actual comparison for eval runs (terminal runs only).
     */
    comparison?: unknown;
};

export type RunDebug = {
    /**
     * Execution phase timeline and structured failure.
     */
    observability: unknown;
    /**
     * Workflow trace id for span lookup (workflow runs only).
     */
    traceId?: string | null;
};

export type RunArtifactsResponse = {
    artifacts: Array<RunArtifact>;
};

export type RunCancelResponse = {
    id: string;
    type: 'workflow' | 'agent';
    /**
     * True when the run has reached a terminal status.
     */
    finished: boolean;
    execution: {
        status: ExecutionStatus;
    };
    cancellation: {
        /**
         * `cancelled` — the run was terminated immediately (it had not started). `requested` — the run is in-flight; cancellation was requested and the status will become `cancelled` shortly. `already_terminal` — the run had already finished; nothing changed.
         */
        state: 'cancelled' | 'requested' | 'already_terminal';
        /**
         * Run status at the time the cancel request was received.
         */
        wasStatus: ExecutionStatus;
    };
};

export type RunEventsResponse = {
    events: Array<RunEvent>;
};

export type RunEvent = {
    type: string;
    timestamp: string;
    status?: string | null;
    message?: string | null;
    metadata?: {
        [key: string]: unknown;
    };
};

export type PromoteRunResponse = {
    /**
     * Automation that owns the promoted example.
     */
    automationId: string;
    /**
     * Implementation type behind the automation.
     */
    automationType: 'workflow' | 'agent';
    /**
     * Dataset example identifier returned for follow-up API calls.
     */
    exampleId: string;
    /**
     * Dataset example name.
     */
    name: string | null;
};

export type RunRerunResponse = RunStartResponse;

export type RunReviewDetail = {
    /**
     * Review metadata and corrections. Corrected files are listed separately at GET /runs/{id}/reviews/expected.
     */
    review: RunReview | null;
};

export type RunReviewExpectedArtifacts = {
    /**
     * Corrected artifact files attached to the run review. Corrected JSON output lives on the review object at GET /runs/{id}/reviews.
     */
    files: Array<RunFile>;
};

/**
 * Corrected file created or renamed by the request.
 */
export type RunReviewExpectedFileMutationResponse = RunFile;

/**
 * Corrected file after the rename.
 */
export type RunReviewExpectedFileUpdateResponse = RunFile;

/**
 * Automated evaluator results attached to a run.
 */
export type RunScoresResponse = {
    /**
     * Automated evaluator scores for the run. These are separate from human review verdicts.
     */
    scores: Array<EvalResult>;
};

export type RunStepsResponse = {
    steps: Array<unknown>;
};

export type RunTraceResponse = {
    /**
     * Chronological trace events. Workflow runs return observability phases or step executions; agent runs return parsed trace.jsonl events.
     */
    events: Array<RunTraceEvent>;
};

/**
 * Trace event emitted by a workflow or agent run. Extra fields depend on the run type and event source.
 */
export type RunTraceEvent = {
    /**
     * Event type when present. Agent traces mirror trace.jsonl events; workflow traces use execution phase or step records.
     */
    type?: string;
    /**
     * Workflow execution phase, when present.
     */
    phase?: string;
    /**
     * Workflow step name, when present.
     */
    stepName?: string;
    /**
     * Event or execution status, when present.
     */
    status?: string;
    /**
     * Event start timestamp.
     */
    startedAt?: string | null;
    /**
     * Event completion timestamp.
     */
    completedAt?: string | null;
    /**
     * Human-readable event message.
     */
    message?: string | null;
    [key: string]: unknown;
};

export type RunUsageResponse = {
    usage: RunUsage | null;
};

